-- ============================================================
--  KRISHI CARE & MANAGEMENT SERVICES PVT. LTD.
--  MASTER SEED SQL v3.0 — Complete, single-file source of truth
--  Includes: All employees, salary, leave balances (from Jan+Feb+Mar registers),
--            attendance data (2029 records), provision system, geofence
--  Run once:  psql -U postgres -d hrms_db -f KRISHI_MASTER_SEED_v3.sql
--  Safe to re-run: all INSERTs use ON CONFLICT
--  Usage:  psql -U postgres -d hrms_db -f master_seed.sql
-- ============================================================
\set ON_ERROR_STOP on

-- ════════════════════════════════════════════════════════════
-- STEP 1 · DESTROY OLD DATABASE (drop all tables + sequences)
-- ════════════════════════════════════════════════════════════
DROP TABLE IF EXISTS loan_recovery_log          CASCADE;
DROP TABLE IF EXISTS advance_approvals          CASCADE;
DROP TABLE IF EXISTS advance_salary             CASCADE;
DROP TABLE IF EXISTS payroll_upload_rows        CASCADE;
DROP TABLE IF EXISTS payroll                    CASCADE;
DROP TABLE IF EXISTS payroll_uploads            CASCADE;
DROP TABLE IF EXISTS employee_salary_structure  CASCADE;
DROP TABLE IF EXISTS attendance_geofence_logs   CASCADE;
DROP TABLE IF EXISTS employee_geofence          CASCADE;
DROP TABLE IF EXISTS office_locations           CASCADE;
DROP TABLE IF EXISTS attendance                 CASCADE;
DROP TABLE IF EXISTS holidays                   CASCADE;
DROP TABLE IF EXISTS leave_requests             CASCADE;
DROP TABLE IF EXISTS leave_balances             CASCADE;
DROP TABLE IF EXISTS leave_types                CASCADE;
DROP TABLE IF EXISTS employee_documents         CASCADE;
DROP TABLE IF EXISTS announcements              CASCADE;
DROP TABLE IF EXISTS separations                CASCADE;
DROP TABLE IF EXISTS notifications              CASCADE;
DROP TABLE IF EXISTS employees                  CASCADE;
DROP TABLE IF EXISTS designations               CASCADE;
DROP TABLE IF EXISTS departments                CASCADE;

-- GK / WFH / Daily tables
DROP TABLE IF EXISTS gk_employee_assignments     CASCADE;
DROP TABLE IF EXISTS gk_daily_responses         CASCADE;
DROP TABLE IF EXISTS gk_daily_questions         CASCADE;
DROP TABLE IF EXISTS gk_daily_thoughts          CASCADE;
DROP TABLE IF EXISTS gk_responses               CASCADE;
DROP TABLE IF EXISTS gk_questions               CASCADE;
DROP TABLE IF EXISTS thought_of_day_schedules   CASCADE;
DROP TABLE IF EXISTS wfh_requests               CASCADE;

SELECT '✅ Old database wiped clean' AS status;

-- ════════════════════════════════════════════════════════════
-- STEP 2 · CREATE SCHEMA
-- ════════════════════════════════════════════════════════════
CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- ── departments ──────────────────────────────────────────────
CREATE TABLE departments (
  id          SERIAL PRIMARY KEY,
  name        VARCHAR(100) NOT NULL UNIQUE,
  code        VARCHAR(20)  UNIQUE,
  description TEXT,
  created_at  TIMESTAMP DEFAULT NOW()
);

-- ── designations ─────────────────────────────────────────────
CREATE TABLE designations (
  id            SERIAL PRIMARY KEY,
  title         VARCHAR(150) NOT NULL,
  department_id INT REFERENCES departments(id) ON DELETE SET NULL,
  grade         VARCHAR(10),
  created_at    TIMESTAMP DEFAULT NOW()
);

-- ── employees ────────────────────────────────────────────────
CREATE TABLE employees (
  id                   SERIAL PRIMARY KEY,
  employee_code        VARCHAR(30)  UNIQUE NOT NULL,
  first_name           VARCHAR(100) NOT NULL,
  last_name            VARCHAR(100) NOT NULL DEFAULT '',
  email                VARCHAR(150) UNIQUE NOT NULL,
  phone                VARCHAR(20),
  gender               VARCHAR(10),
  date_of_birth        DATE,
  city                 VARCHAR(80),
  state                VARCHAR(80),
  department_id        INT REFERENCES departments(id),
  designation_id       INT REFERENCES designations(id),
  reporting_manager_id INT REFERENCES employees(id),
  team_leader_id       INT REFERENCES employees(id),
  employment_type      VARCHAR(30) DEFAULT 'Full-Time',
  joining_date         DATE NOT NULL DEFAULT CURRENT_DATE,
  role                 VARCHAR(20) DEFAULT 'employee'
                         CHECK (role IN ('super_admin','admin','hr','accounts','manager','tl','employee')),
  level                VARCHAR(10),
  password_hash        TEXT NOT NULL,
  is_active            BOOLEAN DEFAULT TRUE,
  pan_number           VARCHAR(15),
  aadhar_number        VARCHAR(25),
  uan_number           VARCHAR(30),
  pf_number            VARCHAR(50),
  bank_name            VARCHAR(100),
  bank_account         VARCHAR(35),
  bank_ifsc            VARCHAR(15),
  basic_salary         NUMERIC(12,2) DEFAULT 0,
  ctc                  NUMERIC(12,2) DEFAULT 0,
  is_wfh_permanent     BOOLEAN NOT NULL DEFAULT false,
  separation_date      DATE,
  separation_type      VARCHAR(30),
  separation_reason    TEXT,
  created_at           TIMESTAMP DEFAULT NOW(),
  updated_at           TIMESTAMP DEFAULT NOW()
);

-- ── leave_types ──────────────────────────────────────────────
CREATE TABLE leave_types (
  id               SERIAL PRIMARY KEY,
  name             VARCHAR(100) NOT NULL,
  code             VARCHAR(20)  UNIQUE NOT NULL,
  days_allowed     INT          NOT NULL DEFAULT 0,
  monthly_accrual  NUMERIC(4,2) DEFAULT 0,
  carry_forward    BOOLEAN      DEFAULT FALSE,
  max_carry_forward INT         DEFAULT 0,
  is_paid          BOOLEAN      DEFAULT TRUE,
  applicable_gender VARCHAR(10) DEFAULT 'all',
  is_active        BOOLEAN      DEFAULT TRUE,
  created_at       TIMESTAMP DEFAULT NOW()
);

-- ── leave_balances ───────────────────────────────────────────
CREATE TABLE leave_balances (
  id             SERIAL PRIMARY KEY,
  employee_id    INT REFERENCES employees(id)   ON DELETE CASCADE,
  leave_type_id  INT REFERENCES leave_types(id) ON DELETE CASCADE,
  year           INT NOT NULL,
  allocated      NUMERIC(6,2) DEFAULT 0,
  used           NUMERIC(6,2) DEFAULT 0,
  pending        NUMERIC(6,2) DEFAULT 0,
  carry_forward  NUMERIC(6,2) DEFAULT 0,
  UNIQUE(employee_id, leave_type_id, year)
);

-- ── leave_requests ───────────────────────────────────────────
CREATE TABLE leave_requests (
  id                   SERIAL PRIMARY KEY,
  employee_id          INT REFERENCES employees(id),
  leave_type_id        INT REFERENCES leave_types(id),
  from_date            DATE NOT NULL,
  to_date              DATE NOT NULL,
  days_requested       NUMERIC(4,1) DEFAULT 1,
  reason               TEXT,
  is_half_day          BOOLEAN DEFAULT FALSE,
  status               VARCHAR(20) DEFAULT 'pending'
                         CHECK (status IN ('pending','approved','rejected','cancelled')),
  approval_chain       JSONB DEFAULT '[]',
  current_approver_code VARCHAR(20),
  actioned_by          INT REFERENCES employees(id),
  actioned_at          TIMESTAMP,
  remarks              TEXT,
  created_at           TIMESTAMP DEFAULT NOW(),
  updated_at           TIMESTAMP DEFAULT NOW()
);

-- ── holidays ─────────────────────────────────────────────────
CREATE TABLE holidays (
  id          SERIAL PRIMARY KEY,
  name        VARCHAR(150) NOT NULL,
  date        DATE         NOT NULL,
  type        VARCHAR(30)  DEFAULT 'National',
  region      VARCHAR(20)  DEFAULT 'all'
                CHECK (region IN ('all','north','south_west')),
  description TEXT,
  year        INT GENERATED ALWAYS AS (EXTRACT(YEAR FROM date)::INT) STORED,
  UNIQUE(date, region)
);

-- ── attendance ───────────────────────────────────────────────
CREATE TABLE attendance (
  id                        SERIAL PRIMARY KEY,
  employee_id               INT REFERENCES employees(id),
  date                      DATE NOT NULL,
  punch_in                  TIME,
  punch_out                 TIME,
  working_hours             NUMERIC(4,2),
  status                    VARCHAR(20) DEFAULT 'present'
    CHECK (status IN ('present','absent','half-day','late','on-leave','od','lwp',
                      'holiday','weekend','regularized')),
  location_lat              NUMERIC(10,6),
  location_lng              NUMERIC(10,6),
  punch_in_location         TEXT,
  punch_out_location        TEXT,
  remarks                   TEXT,
  location_lat_out          NUMERIC(10,6),
  location_lng_out          NUMERIC(10,6),
  is_regularized            BOOLEAN DEFAULT FALSE,
  regularization_reason     TEXT,
  regularization_status     VARCHAR(20) DEFAULT NULL
    CHECK (regularization_status IN ('pending','approved','rejected') OR regularization_status IS NULL),
  regularization_approved_by INT REFERENCES employees(id),
  regularization_applied_at TIMESTAMP,
  regularization_punch_in   TIME          DEFAULT NULL,
  regularization_punch_out  TIME          DEFAULT NULL,
  regularization_requested_at TIMESTAMPTZ DEFAULT NULL,
  regularization_actioned_by  INT REFERENCES employees(id) ON DELETE SET NULL,
  regularization_actioned_at  TIMESTAMPTZ DEFAULT NULL,
  regularization_remarks      TEXT        DEFAULT NULL,
  approved_by               INT REFERENCES employees(id),
  UNIQUE(employee_id, date)
);

-- ── office_locations (geofence) ───────────────────────────────
CREATE TABLE office_locations (
  id             SERIAL PRIMARY KEY,
  name           VARCHAR(150) NOT NULL,
  latitude       NUMERIC(10,7) NOT NULL,
  longitude      NUMERIC(10,7) NOT NULL,
  radius_meters  INT  NOT NULL DEFAULT 100,
  address        TEXT,
  is_active      BOOLEAN DEFAULT TRUE,
  created_by     INT REFERENCES employees(id),
  created_at     TIMESTAMP DEFAULT NOW(),
  updated_at     TIMESTAMP DEFAULT NOW()
);

CREATE TABLE employee_geofence (
  id                 SERIAL PRIMARY KEY,
  employee_id        INT REFERENCES employees(id) ON DELETE CASCADE,
  office_location_id INT REFERENCES office_locations(id) ON DELETE CASCADE,
  is_universal       BOOLEAN DEFAULT FALSE,
  assigned_by        INT REFERENCES employees(id),
  assigned_at        TIMESTAMP DEFAULT NOW(),
  UNIQUE(employee_id, office_location_id)
);

CREATE TABLE attendance_geofence_logs (
  id                 SERIAL PRIMARY KEY,
  employee_id        INT REFERENCES employees(id),
  attendance_id      INT REFERENCES attendance(id),
  punch_type         VARCHAR(10),
  employee_lat       NUMERIC(10,7),
  employee_lng       NUMERIC(10,7),
  distance_meters    INT,
  is_within_geofence BOOLEAN,
  office_location_id INT REFERENCES office_locations(id),
  created_at         TIMESTAMP DEFAULT NOW()
);

-- ── salary structure ──────────────────────────────────────────
-- Stores the monthly salary breakdown per employee (single row per employee)
CREATE TABLE employee_salary_structure (
  id               SERIAL PRIMARY KEY,
  employee_id      INT NOT NULL UNIQUE REFERENCES employees(id) ON DELETE CASCADE,
  -- EARNINGS
  basic            NUMERIC(12,2) DEFAULT 0,
  hra              NUMERIC(12,2) DEFAULT 0,
  conveyance       NUMERIC(12,2) DEFAULT 0,   -- Travel Allowance
  special_allowance NUMERIC(12,2) DEFAULT 0,  -- Other Allow
  gratuity         NUMERIC(12,2) DEFAULT 0,
  gross_salary     NUMERIC(12,2) DEFAULT 0,
  -- EMPLOYEE DEDUCTIONS
  pf_employee      NUMERIC(12,2) DEFAULT 0,   -- 12% of basic, capped ₹1800
  tds              NUMERIC(12,2) DEFAULT 0,   -- Income Tax / TDS
  esi_employee     NUMERIC(12,2) DEFAULT 0,   -- 0.75% gross if gross<=21000
  professional_tax NUMERIC(12,2) DEFAULT 0,   -- ₹200 if gross>=10000
  lwf              NUMERIC(12,2) DEFAULT 0,   -- ₹6/month
  -- EMPLOYER CONTRIBUTIONS
  pf_employer      NUMERIC(12,2) DEFAULT 0,   -- 12% of basic, capped ₹1800
  esi_employer     NUMERIC(12,2) DEFAULT 0,   -- 3.25% gross if gross<=21000
  pf_admin         NUMERIC(12,2) DEFAULT 0,   -- 0.5% of basic, capped ₹75
  total_employer_cost NUMERIC(12,2) DEFAULT 0,
  -- TOTALS
  total_deductions NUMERIC(12,2) DEFAULT 0,   -- all employee deductions
  net_salary       NUMERIC(12,2) DEFAULT 0,   -- net take home
  ctc_monthly      NUMERIC(12,2) DEFAULT 0,
  ctc_annual       NUMERIC(12,2) DEFAULT 0,
  -- Flags
  pf_applicable    BOOLEAN DEFAULT TRUE,
  esi_applicable   BOOLEAN DEFAULT TRUE,
  pt_applicable    BOOLEAN DEFAULT TRUE,
  lwf_applicable   BOOLEAN DEFAULT TRUE,
  tds_applicable   BOOLEAN DEFAULT FALSE,
  notes            TEXT,
  updated_by       INT REFERENCES employees(id),
  updated_at       TIMESTAMP DEFAULT NOW(),
  created_at       TIMESTAMP DEFAULT NOW()
);

-- ── payroll_uploads ───────────────────────────────────────────
CREATE TABLE payroll_uploads (
  id           SERIAL PRIMARY KEY,
  uploaded_by  INT NOT NULL REFERENCES employees(id),
  filename     VARCHAR(255),
  month        SMALLINT,
  year         SMALLINT,
  row_count    INT     DEFAULT 0,
  status       VARCHAR(20) DEFAULT 'processed',
  processed_by INT REFERENCES employees(id),
  processed_at TIMESTAMP,
  notes        TEXT,
  created_at   TIMESTAMP DEFAULT NOW()
);

-- ── payroll ───────────────────────────────────────────────────
-- One row per employee per month — stores exact paid amounts
CREATE TABLE payroll (
  id               SERIAL PRIMARY KEY,
  employee_id      INT REFERENCES employees(id),
  month            INT  NOT NULL,
  year             INT  NOT NULL,
  working_days     NUMERIC(5,1) DEFAULT 0,
  present_days     NUMERIC(5,1) DEFAULT 0,
  lop_days         NUMERIC(5,1) DEFAULT 0,
  paid_days        NUMERIC(5,1) DEFAULT 0,
  -- EARNINGS
  basic            NUMERIC(12,2) DEFAULT 0,
  hra              NUMERIC(12,2) DEFAULT 0,
  conveyance       NUMERIC(12,2) DEFAULT 0,
  special_allowance NUMERIC(12,2) DEFAULT 0,
  gratuity         NUMERIC(12,2) DEFAULT 0,
  gross_salary     NUMERIC(12,2) DEFAULT 0,
  -- EMPLOYEE DEDUCTIONS
  pf_employee      NUMERIC(12,2) DEFAULT 0,
  tds              NUMERIC(12,2) DEFAULT 0,
  esi_employee     NUMERIC(12,2) DEFAULT 0,
  professional_tax NUMERIC(12,2) DEFAULT 0,
  lwf              NUMERIC(12,2) DEFAULT 0,
  loan_emi_recovery NUMERIC(12,2) DEFAULT 0,
  -- EMPLOYER CONTRIBUTIONS
  pf_employer      NUMERIC(12,2) DEFAULT 0,
  esi_employer     NUMERIC(12,2) DEFAULT 0,
  pf_admin         NUMERIC(12,2) DEFAULT 0,
  total_employer_cost NUMERIC(12,2) DEFAULT 0,
  -- TOTALS
  total_deductions NUMERIC(12,2) DEFAULT 0,
  net_salary       NUMERIC(12,2) DEFAULT 0,
  ctc_monthly      NUMERIC(12,2) DEFAULT 0,
  -- Meta
  status           VARCHAR(20) DEFAULT 'paid'
                     CHECK (status IN ('draft','processed','paid','pending')),
  payment_date     DATE,
  upload_id        INT REFERENCES payroll_uploads(id),
  generated_by     INT REFERENCES employees(id),
  generated_at     TIMESTAMP DEFAULT NOW(),
  UNIQUE(employee_id, month, year)
);

-- ── advance_salary (loans) ────────────────────────────────────
CREATE TABLE advance_salary (
  id                  SERIAL PRIMARY KEY,
  employee_id         INT REFERENCES employees(id),
  amount              NUMERIC(12,2) NOT NULL,
  reason              TEXT,
  status              VARCHAR(20) DEFAULT 'approved'
                        CHECK (status IN ('pending','approved','rejected','cleared')),
  approval_chain      JSONB DEFAULT '[]',
  current_approver_code VARCHAR(20),
  current_level       SMALLINT DEFAULT 1,
  monthly_emi         NUMERIC(12,2) DEFAULT 0,
  total_installments  INT DEFAULT 1,
  installments_paid   INT DEFAULT 0,
  balance_remaining   NUMERIC(12,2) DEFAULT 0,
  emi_start_month     INT,
  emi_start_year      INT,
  emi_end_month       INT,
  emi_end_year        INT,
  purpose             TEXT,
  auto_deduct         BOOLEAN DEFAULT TRUE,
  approved_by         INT REFERENCES employees(id),
  approved_at         TIMESTAMP,
  remarks             TEXT,
  requested_at        TIMESTAMP DEFAULT NOW(),
  updated_at          TIMESTAMP DEFAULT NOW()
);

CREATE TABLE advance_approvals (
  id          SERIAL PRIMARY KEY,
  advance_id  INT NOT NULL REFERENCES advance_salary(id) ON DELETE CASCADE,
  level       SMALLINT NOT NULL,
  level_label VARCHAR(30),
  approver_id INT REFERENCES employees(id),
  action      VARCHAR(20) NOT NULL,
  remarks     TEXT,
  acted_at    TIMESTAMP DEFAULT NOW()
);

CREATE TABLE loan_recovery_log (
  id              SERIAL PRIMARY KEY,
  advance_id      INT REFERENCES advance_salary(id),
  employee_id     INT REFERENCES employees(id),
  payroll_month   INT NOT NULL,
  payroll_year    INT NOT NULL,
  emi_amount      NUMERIC(10,2) NOT NULL,
  balance_before  NUMERIC(10,2),
  balance_after   NUMERIC(10,2),
  recovered_at    TIMESTAMP DEFAULT NOW(),
  UNIQUE(advance_id, payroll_month, payroll_year)
);

-- ── notifications ─────────────────────────────────────────────
CREATE TABLE notifications (
  id             SERIAL PRIMARY KEY,
  employee_id    INT REFERENCES employees(id) ON DELETE CASCADE,
  title          VARCHAR(200),
  message        TEXT,
  type           VARCHAR(30) DEFAULT 'info',
  is_read        BOOLEAN DEFAULT FALSE,
  reference_id   INT,
  reference_type VARCHAR(50),
  created_at     TIMESTAMP DEFAULT NOW()
);

-- ── separations ───────────────────────────────────────────────
CREATE TABLE separations (
  id                    SERIAL PRIMARY KEY,
  employee_id           INT REFERENCES employees(id),
  type                  VARCHAR(30)  DEFAULT 'resignation',
  reason                TEXT,
  notice_date           DATE,
  last_working_date     DATE,
  original_lwd          DATE,
  notice_period_days    INT          DEFAULT 30,
  notice_reduced        BOOLEAN      DEFAULT FALSE,
  status                VARCHAR(20)  DEFAULT 'pending'
    CHECK (status IN ('pending','manager_approved','hr_approved',
                      'completed','rejected','withdrawn')),
  -- Who initiated
  initiated_by          INT REFERENCES employees(id),
  initiated_by_role     VARCHAR(20),
  -- Manager approval
  manager_id            INT REFERENCES employees(id),
  manager_action        VARCHAR(20),
  manager_actioned_by   INT REFERENCES employees(id),
  manager_actioned_at   TIMESTAMP,
  manager_remarks       TEXT,
  -- HR approval
  hr_action             VARCHAR(20),
  hr_actioned_by        INT REFERENCES employees(id),
  hr_actioned_at        TIMESTAMP,
  hr_remarks            TEXT,
  -- Withdrawal
  withdrawn_by          INT REFERENCES employees(id),
  withdrawn_at          TIMESTAMP,
  withdrawal_reason     TEXT,
  -- Legacy / admin action
  action_by             INT REFERENCES employees(id),
  action_date           TIMESTAMP,
  -- Timestamps
  created_at            TIMESTAMP DEFAULT NOW(),
  updated_at            TIMESTAMP DEFAULT NOW()
);

-- ── announcements ─────────────────────────────────────────────
CREATE TABLE announcements (
  id            SERIAL PRIMARY KEY,
  title         VARCHAR(200) NOT NULL,
  content       TEXT NOT NULL,
  type          VARCHAR(30) DEFAULT 'general',
  target_role   VARCHAR(20) DEFAULT 'all',
  department_id INT REFERENCES departments(id),
  posted_by     INT REFERENCES employees(id),
  is_active     BOOLEAN DEFAULT TRUE,
  expires_at    DATE,
  created_at    TIMESTAMP DEFAULT NOW()
);

-- ── employee_documents ────────────────────────────────────────
CREATE TABLE employee_documents (
  id            SERIAL PRIMARY KEY,
  employee_id   INT REFERENCES employees(id) ON DELETE CASCADE,
  document_type VARCHAR(80) NOT NULL,
  file_name     VARCHAR(255),
  file_path     VARCHAR(255),
  uploaded_by   INT REFERENCES employees(id),
  uploaded_at   TIMESTAMP DEFAULT NOW(),
  is_verified   BOOLEAN DEFAULT FALSE
);

-- Indexes
-- ── gk_questions ─────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS gk_questions (
  id             SERIAL PRIMARY KEY,
  month          INT NOT NULL CHECK(month BETWEEN 1 AND 12),
  year           INT NOT NULL,
  question       TEXT NOT NULL,
  option_a       TEXT NOT NULL,
  option_b       TEXT NOT NULL,
  option_c       TEXT NOT NULL,
  option_d       TEXT NOT NULL,
  correct_answer CHAR(1) NOT NULL CHECK(correct_answer IN ('A','B','C','D')),
  about          TEXT,
  is_active      BOOLEAN DEFAULT TRUE,
  created_by     INT REFERENCES employees(id),
  created_at     TIMESTAMP DEFAULT NOW(),
  UNIQUE(month, year)
);

-- ── gk_responses ─────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS gk_responses (
  id          SERIAL PRIMARY KEY,
  question_id INT REFERENCES gk_questions(id) ON DELETE CASCADE,
  employee_id INT REFERENCES employees(id)    ON DELETE CASCADE,
  answer      CHAR(1) NOT NULL,
  is_correct  BOOLEAN NOT NULL,
  answered_at TIMESTAMP DEFAULT NOW(),
  UNIQUE(question_id, employee_id)
);

-- ── thought_of_day_schedules ──────────────────────────────────
CREATE TABLE IF NOT EXISTS thought_of_day_schedules (
  id           SERIAL PRIMARY KEY,
  day_number   INT NOT NULL CHECK(day_number BETWEEN 1 AND 366),
  year         INT NOT NULL,
  thought      TEXT NOT NULL,
  author       VARCHAR(200),
  display_date DATE,
  created_at   TIMESTAMP DEFAULT NOW(),
  UNIQUE(day_number, year)
);

-- ── wfh_requests ─────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS wfh_requests (
  id          SERIAL PRIMARY KEY,
  employee_id INT REFERENCES employees(id) ON DELETE CASCADE,
  from_date   DATE NOT NULL,
  to_date     DATE NOT NULL,
  reason      TEXT NOT NULL,
  status      VARCHAR(20) DEFAULT 'pending'
    CHECK(status IN ('pending','approved','rejected','cancelled')),
  actioned_by INT REFERENCES employees(id),
  action_at   TIMESTAMP,
  remarks     TEXT,
  applied_at  TIMESTAMP DEFAULT NOW()
);

-- ── gk_daily_questions ────────────────────────────────────────
CREATE TABLE IF NOT EXISTS gk_daily_questions (
  id             SERIAL PRIMARY KEY,
  question_date  DATE        NOT NULL UNIQUE,
  question       TEXT        NOT NULL,
  option_a       TEXT        NOT NULL,
  option_b       TEXT        NOT NULL,
  option_c       TEXT        NOT NULL,
  option_d       TEXT        NOT NULL,
  correct_answer CHAR(1)     NOT NULL CHECK (correct_answer IN ('A','B','C','D')),
  about          TEXT,
  is_active      BOOLEAN     DEFAULT TRUE,
  created_by     INT         REFERENCES employees(id),
  created_at     TIMESTAMP   DEFAULT NOW()
);

-- ── gk_daily_responses ────────────────────────────────────────
CREATE TABLE IF NOT EXISTS gk_daily_responses (
  id           SERIAL PRIMARY KEY,
  question_id  INT          NOT NULL REFERENCES gk_daily_questions(id) ON DELETE CASCADE,
  employee_id  INT          NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  answer       VARCHAR(5)   NOT NULL,
  is_correct   BOOLEAN      NOT NULL DEFAULT FALSE,
  score_change NUMERIC(6,2) NOT NULL DEFAULT 0,
  answered_at  TIMESTAMP    DEFAULT NOW(),
  UNIQUE (question_id, employee_id)
);

-- ── gk_daily_thoughts ─────────────────────────────────────────
CREATE TABLE IF NOT EXISTS gk_daily_thoughts (
  id           SERIAL PRIMARY KEY,
  thought_date DATE         NOT NULL UNIQUE,
  thought      TEXT         NOT NULL,
  author       VARCHAR(200),
  created_by   INT          REFERENCES employees(id),
  created_at   TIMESTAMP    DEFAULT NOW()
);

-- ── gk_employee_assignments ──────────────────────────────────
-- One random question assigned per employee per day (unique questions)
CREATE TABLE IF NOT EXISTS gk_employee_assignments (
  id            SERIAL PRIMARY KEY,
  employee_id   INT          NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  question_id   INT          NOT NULL REFERENCES gk_daily_questions(id) ON DELETE CASCADE,
  assigned_date DATE         NOT NULL DEFAULT CURRENT_DATE,
  created_at    TIMESTAMP    DEFAULT NOW(),
  UNIQUE (employee_id, assigned_date)
);

-- ── Extra columns on announcements ───────────────────────────
ALTER TABLE announcements
  ADD COLUMN IF NOT EXISTS image_url          TEXT,
  ADD COLUMN IF NOT EXISTS link_url           TEXT,
  ADD COLUMN IF NOT EXISTS link_label         VARCHAR(100),
  ADD COLUMN IF NOT EXISTS thought_day_number INT;

CREATE INDEX IF NOT EXISTS idx_emp_dept      ON employees(department_id);
CREATE INDEX IF NOT EXISTS idx_emp_manager   ON employees(reporting_manager_id);
CREATE INDEX IF NOT EXISTS idx_att_emp_date  ON attendance(employee_id, date);
CREATE INDEX IF NOT EXISTS idx_leave_emp     ON leave_requests(employee_id);
CREATE INDEX IF NOT EXISTS idx_payroll_emp   ON payroll(employee_id, month, year);
CREATE INDEX IF NOT EXISTS idx_notif_emp     ON notifications(employee_id);
CREATE INDEX IF NOT EXISTS idx_adv_emp       ON advance_salary(employee_id);
CREATE INDEX IF NOT EXISTS idx_gk_resp_emp   ON gk_responses(employee_id);
CREATE INDEX IF NOT EXISTS idx_wfh_emp       ON wfh_requests(employee_id);
CREATE INDEX IF NOT EXISTS idx_wfh_status    ON wfh_requests(status);
CREATE INDEX IF NOT EXISTS idx_gkdq_date     ON gk_daily_questions(question_date);
CREATE INDEX IF NOT EXISTS idx_gkdr_emp      ON gk_daily_responses(employee_id);
CREATE INDEX IF NOT EXISTS idx_gkdr_qid      ON gk_daily_responses(question_id);
