SELECT e.id,lt.id,2026,0,0,0,0 FROM employees e CROSS JOIN leave_types lt
WHERE e.is_active=TRUE AND lt.code='OD' AND lt.is_active=TRUE
ON CONFLICT(employee_id,leave_type_id,year) DO NOTHING;
SELECT e.id,lt.id,2026,0,0,0,0 FROM employees e CROSS JOIN leave_types lt
WHERE e.is_active=TRUE AND e.gender='Female' AND lt.code='ML' AND lt.is_active=TRUE
ON CONFLICT(employee_id,leave_type_id,year) DO NOTHING;
SELECT '✅ Leave balances seeded from actual attendance registers' AS status;

-- ════════════════════════════════════════════════════════════
-- STEP 12B · PROVISION SYSTEM — New columns, tables, leave type
-- ════════════════════════════════════════════════════════════

-- Add employee_category column
ALTER TABLE employees
  ADD COLUMN IF NOT EXISTS employee_category VARCHAR(20) DEFAULT 'permanent'
    CHECK (employee_category IN ('permanent','provision','contractual'));
ALTER TABLE employees ADD COLUMN IF NOT EXISTS provision_end_date DATE DEFAULT NULL;
ALTER TABLE employees ADD COLUMN IF NOT EXISTS confirmed_date     DATE DEFAULT NULL;

-- Provision Leave type (1/month × 6 months max)
VALUES ('Provision Leave','PL',6,1.0,FALSE,0,TRUE,'all')
ON CONFLICT(code) DO NOTHING;

-- Provision confirmation workflow table (Manager → HR → auto-confirm)
CREATE TABLE IF NOT EXISTS provision_confirmations (
  id                   SERIAL PRIMARY KEY,
  employee_id          INT NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  manager_id           INT REFERENCES employees(id),
  manager_approved_at  TIMESTAMP,
  manager_remarks      TEXT,
  manager_status       VARCHAR(20) DEFAULT 'pending'
    CHECK (manager_status IN ('pending','approved','rejected')),
  hr_id                INT REFERENCES employees(id),
  hr_approved_at       TIMESTAMP,
  hr_remarks           TEXT,
  hr_status            VARCHAR(20) DEFAULT 'pending'
    CHECK (hr_status IN ('pending','approved','rejected')),
  overall_status       VARCHAR(20) DEFAULT 'pending'
    CHECK (overall_status IN ('pending','manager_approved','hr_approved','confirmed','rejected')),
  initiated_by         INT REFERENCES employees(id),
  initiated_at         TIMESTAMP DEFAULT NOW(),
  confirmed_at         TIMESTAMP,
  notes                TEXT,
  UNIQUE(employee_id)
);

-- Monthly leave accrual log (prevents double-accrual)
CREATE TABLE IF NOT EXISTS monthly_leave_accrual_log (
  id            SERIAL PRIMARY KEY,
  employee_id   INT NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  month         SMALLINT NOT NULL,
  year          SMALLINT NOT NULL,
  accrual_type  VARCHAR(20) DEFAULT 'standard',
  el_accrued    NUMERIC(4,2) DEFAULT 0,
  sl_accrued    NUMERIC(4,2) DEFAULT 0,
  cl_accrued    NUMERIC(4,2) DEFAULT 0,
  pl_accrued    NUMERIC(4,2) DEFAULT 0,
  accrued_at    TIMESTAMP DEFAULT NOW(),
  accrued_by    INT REFERENCES employees(id),
  notes         TEXT,
  UNIQUE(employee_id, month, year)
);

-- Classify provision employees (based on joining date within last 6 months)
UPDATE employees SET employee_category='provision',
  provision_end_date = joining_date + INTERVAL '6 months'
WHERE employee_code IN ('KC9040','KC4430','KC9041','KC9082');

-- Mark past provision employees as permanent
UPDATE employees SET employee_category='permanent',
  provision_end_date = joining_date + INTERVAL '6 months',
  confirmed_date     = joining_date + INTERVAL '6 months'
WHERE employee_code IN ('KC8977','KC8986','KC8999')
  AND (joining_date + INTERVAL '6 months') <= CURRENT_DATE;

-- Everyone else = permanent (default)
UPDATE employees SET employee_category='permanent'
WHERE employee_category IS NULL OR employee_category='permanent';

SELECT '✅ Provision system tables and employee categories set' AS status;




