-- STEP 15 · ADVANCE SALARY APPROVAL CHAINS
-- Fix DIRECT_TO_COO employees (KC8989, KC4432, KC1041, KC9040, KC7708)
-- Their chain = COO → MD → Accounts (3 levels) — NEVER 4
-- ════════════════════════════════════════════════════════════

-- Fix ALL advance records (any status) for these 5 employees
UPDATE advance_salary
SET
  approval_chain = '["KC718","KC01","KC7708"]',
  updated_at     = NOW()
WHERE employee_id IN (
  SELECT id FROM employees
  WHERE employee_code IN ('KC8989','KC4432','KC1041','KC9040','KC7708')
    AND is_active = true
);

-- Reset pending ones to Level 1 / COO
UPDATE advance_salary
SET
  current_approver_code = 'KC718',
  current_level         = 1,
  updated_at            = NOW()
WHERE status = 'pending'
  AND employee_id IN (
    SELECT id FROM employees
    WHERE employee_code IN ('KC8989','KC4432','KC1041','KC9040','KC7708')
      AND is_active = true
  );

-- Delete bogus Manager-level approval logs for these employees
DELETE FROM advance_approvals
WHERE advance_id IN (
  SELECT a.id FROM advance_salary a
  JOIN employees e ON a.employee_id = e.id
  WHERE e.employee_code IN ('KC8989','KC4432','KC1041','KC9040','KC7708')
)
AND level = 1
AND level_label NOT IN ('KC718','KC01','KC7708');

SELECT '✅ Advance approval chains fixed for DIRECT_TO_COO employees' AS status;

-- ════════════════════════════════════════════════════════════
-- STEP 16 · LEAVE APPROVAL CHAINS
-- Fix any pending leave requests that got the wrong chain
-- (went to COO instead of their direct manager)
-- ════════════════════════════════════════════════════════════

-- Employees whose manager is KC8989 (Akshay): fix pending leaves
-- that wrongly point to KC718 (COO) as current approver
UPDATE leave_requests
SET
  approval_chain        = '["KC8989","KC718"]',
  current_approver_code = 'KC8989',
  updated_at            = NOW()
WHERE status = 'pending'
  AND employee_id IN (
    SELECT id FROM employees
    WHERE reporting_manager_id = (
      SELECT id FROM employees WHERE employee_code = 'KC8989'
    )
  )
  AND current_approver_code = 'KC718';

-- Generic fix: any pending leave where current_approver is COO
-- but the employee's actual manager is NOT the COO
UPDATE leave_requests lr
SET
  approval_chain        = json_build_array(
    (SELECT m.employee_code FROM employees e
     JOIN employees m ON e.reporting_manager_id = m.id
     WHERE e.id = lr.employee_id),
    'KC718'
  )::jsonb,
  current_approver_code = (
    SELECT m.employee_code FROM employees e
    JOIN employees m ON e.reporting_manager_id = m.id
    WHERE e.id = lr.employee_id
  ),
  updated_at = NOW()
WHERE lr.status = 'pending'
  AND lr.current_approver_code = 'KC718'
  AND lr.employee_id IN (
    SELECT e.id FROM employees e
    JOIN employees m ON e.reporting_manager_id = m.id
    WHERE m.employee_code != 'KC718'
      AND m.employee_code IS NOT NULL
  );

SELECT '✅ Leave approval chains fixed' AS status;

