  ('Sick Leave',        'SL',   6, 0.5,  FALSE, 0,  TRUE,  'all',    TRUE),
  ('Casual Leave',      'CL',   6, 0.5,  FALSE, 0,  TRUE,  'all',    TRUE),
  ('Maternity Leave',   'ML',  90, 0.0,  FALSE, 0,  TRUE,  'female', TRUE),
  ('Leave Without Pay', 'LWP',  0, 0.0,  FALSE, 0,  FALSE, 'all',    TRUE)
) AS v(name, code, days_allowed, monthly_accrual, carry_forward, max_carry_forward, is_paid, applicable_gender, is_active)
WHERE NOT EXISTS (SELECT 1 FROM leave_types WHERE code = v.code);

