-- ════════════════════════════════════════════════════════════
SELECT 'leave_types'    AS check_item, COUNT(*) AS count FROM leave_types WHERE is_active = TRUE;
SELECT 'advance_chains' AS check_item, COUNT(*) AS count
  FROM advance_salary a
  JOIN employees e ON a.employee_id = e.id
  WHERE e.employee_code IN ('KC8989','KC4432','KC1041','KC9040','KC7708')
    AND jsonb_array_length(a.approval_chain) = 3;

