-- ════════════════════════════════════════════════════════════
-- STEP 21 · OD REQUESTS TABLE (Outdoor Duty approval workflow)
-- ════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS od_requests (
  id          SERIAL PRIMARY KEY,
  employee_id INT  NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  date        DATE NOT NULL,
  reason      TEXT NOT NULL,
  location    VARCHAR(255) DEFAULT 'Outdoor Duty',
  status      VARCHAR(20)  DEFAULT 'pending'
    CHECK(status IN ('pending','approved','rejected','cancelled')),
  actioned_by INT  REFERENCES employees(id),
  action_at   TIMESTAMPTZ,
  remarks     TEXT,
  applied_at  TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(employee_id, date)
);

CREATE INDEX IF NOT EXISTS idx_od_emp_date ON od_requests(employee_id, date);
CREATE INDEX IF NOT EXISTS idx_od_status   ON od_requests(status);

SELECT '✅ od_requests table created' AS status;

-- STEP 22 · BIRTHDAY WISHES & LIKES TABLES
-- ════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS birthday_wishes (
  id              SERIAL PRIMARY KEY,
  birthday_emp_id INTEGER NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  from_emp_id     INTEGER NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  wish_date       DATE    NOT NULL DEFAULT CURRENT_DATE,
  message         TEXT,
  created_at      TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(birthday_emp_id, from_emp_id, wish_date)
);

CREATE TABLE IF NOT EXISTS birthday_likes (
  id              SERIAL PRIMARY KEY,
  birthday_emp_id INTEGER NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  from_emp_id     INTEGER NOT NULL REFERENCES employees(id) ON DELETE CASCADE,
  like_date       DATE    NOT NULL DEFAULT CURRENT_DATE,
  created_at      TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(birthday_emp_id, from_emp_id, like_date)
);

CREATE INDEX IF NOT EXISTS idx_emp_dob_month_day
  ON employees(EXTRACT(MONTH FROM date_of_birth), EXTRACT(DAY FROM date_of_birth))
  WHERE date_of_birth IS NOT NULL AND is_active = TRUE;

SELECT '✅ Birthday tables created' AS status;

