-- ════════════════════════════════════════════════════════════
-- ONE-TIME FIX: Update any existing 'wfh' status records for
-- permanent WFH employees to 'present' with correct punch times
-- Run ONCE on existing databases (safe to re-run — idempotent)
-- ════════════════════════════════════════════════════════════
UPDATE attendance a
SET status             = 'present',
    punch_in           = COALESCE(a.punch_in, '09:30:00'),
    punch_out          = COALESCE(a.punch_out, '18:30:00'),
    working_hours      = COALESCE(a.working_hours, 9.0),
    punch_in_location  = COALESCE(a.punch_in_location, 'Work from Home'),
    punch_out_location = COALESCE(a.punch_out_location, 'Work from Home'),
    wfh_approved       = true
FROM employees e
WHERE a.employee_id = e.id
  AND e.is_wfh_permanent = true
  AND a.status = 'wfh';

SELECT '✅ One-time fix: permanent WFH attendance status corrected to present' AS status;

